  {id:'R1', awaddr_offset:4068.56, awlen:15, awsize_bytes:8.18, boundary_cross:1},
  {id:'R2', awaddr_offset:3966.6, awlen:5, awsize_bytes:4.79, boundary_cross:1},
  {id:'R3', awaddr_offset:4076.78, awlen:7, awsize_bytes:5.52, boundary_cross:0},
  {id:'R4', awaddr_offset:4035.08, awlen:2, awsize_bytes:5.28, boundary_cross:1},
];
const threshold = 45.0;
for (const r of records) {
  r.burst_bytes = +(r.awlen * r.awsize_bytes).toFixed(4);
  r.priority_proxy = +(r.awaddr_offset + r.burst_bytes + threshold * r.boundary_cross).toFixed(4);
  r.class = r.boundary_cross ? 'gap_present' : 'gap_not_observed';
  r.sens = {
    awaddr_offset: +(r.awaddr_offset * 1.05).toFixed(4),
    awlen: +(r.awlen * 1.05).toFixed(4),
    awsize_bytes: +(r.awsize_bytes * 1.05).toFixed(4),
  };
  r.sens_burst_bytes = +(r.sens.awlen * r.sens.awsize_bytes).toFixed(4);
  r.sens_priority_proxy = +(r.sens.awaddr_offset + r.sens_burst_bytes + threshold * r.boundary_cross).toFixed(4);
  r.sens_class = r.class;
}
const ranked = [...records].sort((a,b)=>b.priority_proxy-a.priority_proxy).map(r=>r.id);
const options = [
  {id:'O1', driver:'awaddr_offset', reduction_pct:12, cost:13175},
  {id:'O2', driver:'awlen', reduction_pct:18, cost:19975},
  {id:'O3', driver:'boundary_cross_margin', reduction_pct:9, cost:22950},
];
for (const o of options) o.efficiency = +(o.reduction_pct / o.cost).toExponential(6);
const combos = [];
for (let mask=1; mask<8; mask++) {
  const picked = options.filter((_,i)=>mask>>i & 1);
  const cost = picked.reduce((s,o)=>s+o.cost,0);
  const reduction = picked.reduce((s,o)=>s+o.reduction_pct,0);
